// WF98 validates protected runtime configuration before querying PostgreSQL.

function readBoundedInteger(name, fallback) {
  const rawValue = $env[name];

  const value =
    rawValue === null ||
    rawValue === undefined ||
    String(rawValue).trim() === ''
      ? fallback
      : Number(rawValue);

  if (
    !Number.isInteger(value) ||
    value < 1 ||
    value > 200
  ) {
    throw new Error(
      `${name} must be an integer between 1 and 200`,
    );
  }

  return value;
}

const batchSize = readBoundedInteger(
  'WF98_BATCH_SIZE',
  50,
);

const maxDispatchesPerRun = readBoundedInteger(
  'WF98_MAX_DISPATCHES_PER_RUN',
  50,
);

const waitForCompletion = String(
  $env.WF98_DESTINATION_WAIT_FOR_COMPLETION ??
    'false',
)
  .trim()
  .toLowerCase();

if (waitForCompletion !== 'false') {
  throw new Error(
    'WF98_DESTINATION_WAIT_FOR_COMPLETION must be false',
  );
}

return [
  {
    json: {
      workflow_name: 'WF98 — Retry Dispatcher',
      started_at: new Date().toISOString(),

      batch_size: batchSize,

      max_dispatches_per_run:
        maxDispatchesPerRun,

      operation_candidate_limit: Math.min(
        batchSize,
        maxDispatchesPerRun,
      ),

      destination_wait_for_completion: false,
    },
  },
];

// Validate one WF98 candidate and build a minimal safe dispatch payload.

const candidate = $json;

const UUID_PATTERN =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

function isUuid(value) {
  return (
    typeof value === 'string' &&
    UUID_PATTERN.test(value)
  );
}

function requireUuid(value, fieldName) {
  if (!isUuid(value)) {
    return {
      valid: false,
      errorCode: `invalid_${fieldName}`,
    };
  }

  return {
    valid: true,
  };
}

function safeText(value, maxLength = 200) {
  if (
    value === null ||
    value === undefined
  ) {
    return null;
  }

  if (
    typeof value !== 'string' &&
    typeof value !== 'number' &&
    typeof value !== 'boolean'
  ) {
    return null;
  }

  const normalized = String(value).trim();

  if (!normalized) {
    return null;
  }

  return normalized.slice(0, maxLength);
}

function integrityFailure(errorCode) {
  return {
    json: {
      dispatch_kind: 'integrity_failure',
      dispatch_status: 'ready',
      integrity_failure: true,

      destination_workflow: 'WF99',

      candidate_source: safeText(
        candidate.candidate_source,
        100,
      ),

      candidate_class: safeText(
        candidate.candidate_class,
        100,
      ),

      external_operation_id: isUuid(
        candidate.external_operation_id,
      )
        ? candidate.external_operation_id
        : null,

      operation_type: safeText(
        candidate.operation_type,
        100,
      ),

      case_id: isUuid(candidate.case_id)
        ? candidate.case_id
        : null,

      correlation_id: isUuid(
        candidate.correlation_id,
      )
        ? candidate.correlation_id
        : null,

      payload: {
        source_variant: 'explicit_internal',

        source_workflow_name:
          'WF98 — Retry Dispatcher',

        source_workflow_id: safeText(
          $workflow.id,
          120,
        ),

        source_execution_id: safeText(
          $execution.id,
          120,
        ),

        case_id: isUuid(candidate.case_id)
          ? candidate.case_id
          : null,

        correlation_id: isUuid(
          candidate.correlation_id,
        )
          ? candidate.correlation_id
          : null,

        step_id: isUuid(candidate.step_id)
          ? candidate.step_id
          : null,

        submission_id: isUuid(
          candidate.submission_id,
        )
          ? candidate.submission_id
          : null,

        external_operation_id: isUuid(
          candidate.external_operation_id,
        )
          ? candidate.external_operation_id
          : null,

        error_class:
          'wf98_candidate_integrity_error',

        error_code: errorCode,

        error_message:
          `WF98 rejected a malformed or unsupported retry candidate: ${errorCode}`,

        retryable: false,
        severity: 'critical',
        requires_intervention: true,

        error_details: {
          candidate_source: safeText(
            candidate.candidate_source,
            100,
          ),

          candidate_class: safeText(
            candidate.candidate_class,
            100,
          ),

          operation_type: safeText(
            candidate.operation_type,
            100,
          ),

          destination_workflow: safeText(
            candidate.destination_workflow,
            100,
          ),
        },
      },
    },
  };
}

const operationDestinations = {
  send_client_data_request: 'WF02',
  send_approval_request: 'WF04',
  provision_client: 'WF05',
  create_drive_folder: 'WF06',
  create_kickoff_event: 'WF06',
  notify_team: 'WF06',
  notify_operator_intervention: 'WF99',
};

if (
  candidate.candidate_source ===
  'external_operation'
) {
  const operationIdCheck = requireUuid(
    candidate.external_operation_id,
    'external_operation_id',
  );

  if (!operationIdCheck.valid) {
    return integrityFailure(
      operationIdCheck.errorCode,
    );
  }

  const expectedDestination =
    operationDestinations[
      candidate.operation_type
    ];

  if (!expectedDestination) {
    return integrityFailure(
      'unknown_operation_type',
    );
  }

  if (
    candidate.destination_workflow !==
    expectedDestination
  ) {
    return integrityFailure(
      'destination_mapping_mismatch',
    );
  }

  if (
    candidate.operation_type ===
    'notify_operator_intervention'
  ) {
    return {
      json: {
        dispatch_kind: 'operation_retry',
        dispatch_status: 'ready',
        integrity_failure: false,

        destination_workflow: 'WF99',

        candidate_source:
          candidate.candidate_source,

        candidate_class:
          candidate.candidate_class,

        external_operation_id:
          candidate.external_operation_id,

        operation_type:
          candidate.operation_type,

        case_id:
          candidate.case_id ?? null,

        correlation_id:
          candidate.correlation_id ?? null,

        payload: {
          source_variant:
            'notification_retry',

          trigger_source: 'wf98',

          external_operation_id:
            candidate.external_operation_id,
        },
      },
    };
  }

  const caseIdCheck = requireUuid(
    candidate.case_id,
    'case_id',
  );

  if (!caseIdCheck.valid) {
    return integrityFailure(
      caseIdCheck.errorCode,
    );
  }

  const correlationIdCheck = requireUuid(
    candidate.correlation_id,
    'correlation_id',
  );

  if (!correlationIdCheck.valid) {
    return integrityFailure(
      correlationIdCheck.errorCode,
    );
  }

  return {
    json: {
      dispatch_kind: 'operation_retry',
      dispatch_status: 'ready',
      integrity_failure: false,

      destination_workflow:
        expectedDestination,

      candidate_source:
        candidate.candidate_source,

      candidate_class:
        candidate.candidate_class,

      external_operation_id:
        candidate.external_operation_id,

      operation_type:
        candidate.operation_type,

      case_id:
        candidate.case_id,

      correlation_id:
        candidate.correlation_id,

      payload: {
        case_id:
          candidate.case_id,

        correlation_id:
          candidate.correlation_id,

        external_operation_id:
          candidate.external_operation_id,

        trigger_source: 'wf98',
      },
    },
  };
}

if (
  candidate.candidate_source ===
  'state_gap'
) {
  const caseIdCheck = requireUuid(
    candidate.case_id,
    'case_id',
  );

  if (!caseIdCheck.valid) {
    return integrityFailure(
      caseIdCheck.errorCode,
    );
  }

  const correlationIdCheck = requireUuid(
    candidate.correlation_id,
    'correlation_id',
  );

  if (!correlationIdCheck.valid) {
    return integrityFailure(
      correlationIdCheck.errorCode,
    );
  }

  const basePayload = {
    case_id:
      candidate.case_id,

    correlation_id:
      candidate.correlation_id,

    trigger_source: 'wf98',

    recovery_reason:
      candidate.recovery_reason,
  };

  if (
    candidate.candidate_class ===
    'pending_submission_validation'
  ) {
    if (
      candidate.destination_workflow !==
      'WF03'
    ) {
      return integrityFailure(
        'destination_mapping_mismatch',
      );
    }

    const submissionIdCheck = requireUuid(
      candidate.submission_id,
      'submission_id',
    );

    if (!submissionIdCheck.valid) {
      return integrityFailure(
        submissionIdCheck.errorCode,
      );
    }

    return {
      json: {
        dispatch_kind: 'state_gap',
        dispatch_status: 'ready',
        integrity_failure: false,

        destination_workflow: 'WF03',

        candidate_source:
          candidate.candidate_source,

        candidate_class:
          candidate.candidate_class,

        case_id:
          candidate.case_id,

        correlation_id:
          candidate.correlation_id,

        payload: {
          ...basePayload,

          submission_id:
            candidate.submission_id,
        },
      },
    };
  }

  if (
    candidate.candidate_class ===
    'missing_initial_client_data_dispatch'
  ) {
    if (
      candidate.destination_workflow !==
        'WF02' ||
      candidate.request_cycle_key !==
        'initial'
    ) {
      return integrityFailure(
        'invalid_initial_client_data_gap',
      );
    }

    return {
      json: {
        dispatch_kind: 'state_gap',
        dispatch_status: 'ready',
        integrity_failure: false,

        destination_workflow: 'WF02',

        candidate_source:
          candidate.candidate_source,

        candidate_class:
          candidate.candidate_class,

        case_id:
          candidate.case_id,

        correlation_id:
          candidate.correlation_id,

        payload: {
          ...basePayload,

          request_cycle_key: 'initial',
        },
      },
    };
  }

  if (
    candidate.candidate_class ===
    'missing_correction_dispatch'
  ) {
    if (
      candidate.destination_workflow !==
      'WF02'
    ) {
      return integrityFailure(
        'destination_mapping_mismatch',
      );
    }

    const failedSubmissionCheck =
      requireUuid(
        candidate.failed_submission_id,
        'failed_submission_id',
      );

    if (!failedSubmissionCheck.valid) {
      return integrityFailure(
        failedSubmissionCheck.errorCode,
      );
    }

    const expectedCycleKey =
      `validation_failed:${candidate.failed_submission_id}`;

    if (
      candidate.request_cycle_key !==
      expectedCycleKey
    ) {
      return integrityFailure(
        'request_cycle_key_mismatch',
      );
    }

    return {
      json: {
        dispatch_kind: 'state_gap',
        dispatch_status: 'ready',
        integrity_failure: false,

        destination_workflow: 'WF02',

        candidate_source:
          candidate.candidate_source,

        candidate_class:
          candidate.candidate_class,

        case_id:
          candidate.case_id,

        correlation_id:
          candidate.correlation_id,

        payload: {
          ...basePayload,

          request_cycle_key:
            candidate.request_cycle_key,

          failed_submission_id:
            candidate.failed_submission_id,
        },
      },
    };
  }

  const fixedStateGapDestinations = {
    missing_approval_dispatch: 'WF04',
    missing_provisioning_dispatch: 'WF05',
    missing_finalization_dispatch: 'WF06',
    resume_finalization: 'WF06',
    complete_finalization: 'WF06',
  };

  const expectedDestination =
    fixedStateGapDestinations[
      candidate.candidate_class
    ];

  if (!expectedDestination) {
    return integrityFailure(
      'unknown_state_gap_type',
    );
  }

  if (
    candidate.destination_workflow !==
    expectedDestination
  ) {
    return integrityFailure(
      'destination_mapping_mismatch',
    );
  }

  return {
    json: {
      dispatch_kind: 'state_gap',
      dispatch_status: 'ready',
      integrity_failure: false,

      destination_workflow:
        expectedDestination,

      candidate_source:
        candidate.candidate_source,

      candidate_class:
        candidate.candidate_class,

      case_id:
        candidate.case_id,

      correlation_id:
        candidate.correlation_id,

      payload: basePayload,
    },
  };
}

return integrityFailure(
  'unknown_candidate_source',
);

// Build a sanitized WF98 summary when no candidates were selected.

function readBoundedInteger(name, fallback) {
  const rawValue = $env[name];

  const value =
    rawValue === null ||
    rawValue === undefined ||
    String(rawValue).trim() === ''
      ? fallback
      : Number(rawValue);

  if (
    !Number.isInteger(value) ||
    value < 1 ||
    value > 200
  ) {
    throw new Error(
      `${name} must be an integer between 1 and 200`,
    );
  }

  return value;
}

const batchSize = readBoundedInteger(
  'WF98_BATCH_SIZE',
  50,
);

const maxDispatchesPerRun = readBoundedInteger(
  'WF98_MAX_DISPATCHES_PER_RUN',
  50,
);

const startedAt =
  $execution.startedAt instanceof Date
    ? $execution.startedAt.toISOString()
    : new Date(
        $execution.startedAt ?? Date.now(),
      ).toISOString();

return [
  {
    json: {
      workflow: 'WF98',
      result: 'completed',

      selected_count: 0,
      dispatch_accepted_count: 0,
      dispatch_failed_count: 0,
      integrity_failure_count: 0,

      batch_limit: Math.min(
        batchSize,
        maxDispatchesPerRun,
      ),

      started_at: startedAt,
      finished_at: new Date().toISOString(),
    },
  },
];

// Pass only the validated payload to WF02.
// Internal WF98 routing fields must not leave this workflow.

const payload = $json.payload;

if (
  payload === null ||
  typeof payload !== 'object' ||
  Array.isArray(payload)
) {
  throw new Error(
    'WF98 dispatch payload for WF02 must be a JSON object',
  );
}

return {
  json: payload,
};

// Pass only the validated payload to the destination workflow.
// Internal WF98 routing fields must not leave WF98.

const payload = $json.payload;

if (
