// Build one sanitized WF98 summary after all dispatch attempts finish.

function readBoundedInteger(name, fallback) {
  const rawValue = $env[name];

  const value =
    rawValue === null ||
    rawValue === undefined ||
    String(rawValue).trim() === ''
      ? fallback
      : Number(rawValue);

  if (
    !Number.isInteger(value) ||
    value < 1 ||
    value > 200
  ) {
    throw new Error(
      `${name} must be an integer between 1 and 200`,
    );
  }

  return value;
}

const items = $input.all();

const selectedCount = items.length;

const dispatchAcceptedCount = items.filter(
  (item) =>
    item.json?.dispatch_outcome === 'accepted',
).length;

const dispatchFailedCount = items.filter(
  (item) =>
    item.json?.dispatch_outcome === 'failed',
).length;

const classifiedCount =
  dispatchAcceptedCount + dispatchFailedCount;

if (classifiedCount !== selectedCount) {
  throw new Error(
    `WF98 summary expected ${selectedCount} classified dispatch results, received ${classifiedCount}`,
  );
}

const integrityFailureCount = items.filter(
  (item) =>
    item.json?.integrity_failure === true,
).length;

const batchSize = readBoundedInteger(
  'WF98_BATCH_SIZE',
  50,
);

const maxDispatchesPerRun = readBoundedInteger(
  'WF98_MAX_DISPATCHES_PER_RUN',
  50,
);

const startedAt =
  $execution.startedAt instanceof Date
    ? $execution.startedAt.toISOString()
    : new Date(
        $execution.startedAt ?? Date.now(),
      ).toISOString();

return [
  {
    json: {
      workflow: 'WF98',
      result: 'completed',

      selected_count: selectedCount,
      dispatch_accepted_count:
        dispatchAcceptedCount,
      dispatch_failed_count:
        dispatchFailedCount,
      integrity_failure_count:
        integrityFailureCount,

      batch_limit: Math.min(
        batchSize,
        maxDispatchesPerRun,
      ),

      started_at: startedAt,
      finished_at: new Date().toISOString(),
    },
  },
];
